section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-test-strategy-template.json",
  "type": "object",
  "title": "QA Test Strategy Template",
  "required": [
    "feature_id",
    "risks",
    "out_of_scope",
    "layers_in_scope",
    "page_length_words",
    "last_reviewed"
  ],
  "additionalProperties": false,
  "properties": {
    "feature_id": {
      "type": "string",
      "minLength": 1,
      "description": "Feature identifier."
    },
    "risks": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {id, description, severity, layers, owner, exit_criterion}."
    },
    "out_of_scope": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {item, reason}."
    },
    "layers_in_scope": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Subset of allowed layers."
    },
    "page_length_words": {
      "type": "integer",
      "description": "Word count; \u22641000."
    },
    "last_reviewed": {
      "type": "string",
      "minLength": 1,
      "description": "ISO date."
    }
  }
}

example.code:
{
  "feature_id": "f-bulk-role-edit",
  "risks": [
    {
      "id": "r1",
      "description": "Bulk action ignores active filter",
      "severity": "S1",
      "layers": [
        "integration",
        "e2e"
      ],
      "owner": "alice",
      "exit_criterion": "5 e2e cases green; 2 integration cases green"
    }
  ],
  "out_of_scope": [
    {
      "item": "perf > 1k rows",
      "reason": "Beyond v2.4 scope; tracked in F-091."
    }
  ],
  "layers_in_scope": [
    "unit",
    "integration",
    "e2e"
  ],
  "page_length_words": 720,
  "last_reviewed": "2026-05-23"
}
